begin;

create extension if not exists pgtap with schema extensions;
set search_path = public, extensions;
select plan(15);






select is((select count(*)::integer from public.search_evidence_for_generation('61aaaaaa-0000-4000-8000-000000000001','61420000-0000-4000-8000-000000000001','access reviewed quarterly',12)),1,'Service retrieval returns eligible tenant evidence and excludes restricted evidence for contributor requesters');
select ok(not exists(select 1 from public.retrieval_candidates where tenant_id='62bbbbbb-0000-4000-8000-000000000001'),'Service retrieval never creates another tenant candidate');
select throws_ok($$select * from public.search_evidence_for_generation('62bbbbbb-0000-4000-8000-000000000001','61420000-0000-4000-8000-000000000001','access',5)$$,'P0002','Generation run not found','Cross-tenant run lookup fails closed');
select lives_ok($$select public.persist_generation_input('61aaaaaa-0000-4000-8000-000000000001','61420000-0000-4000-8000-000000000001',repeat('a',64),jsonb_build_object('tenantId','61aaaaaa-0000-4000-8000-000000000001','generationRunId','61420000-0000-4000-8000-000000000001','questionnaireSnapshotId','61250000-0000-4000-8000-000000000001','questionId','61230000-0000-4000-8000-000000000001','snapshotHash',repeat('6',64)),jsonb_build_array(jsonb_build_object('spanId','61340000-0000-4000-8000-000000000001','evidenceVersionId','61320000-0000-4000-8000-000000000001','retrievalRunId',(select id from public.retrieval_runs where tenant_id='61aaaaaa-0000-4000-8000-000000000001' limit 1),'candidateOrder',1)))$$,'First immutable input persistence succeeds');
select lives_ok($$select public.persist_generation_input('61aaaaaa-0000-4000-8000-000000000001','61420000-0000-4000-8000-000000000001',repeat('a',64),jsonb_build_object('tenantId','61aaaaaa-0000-4000-8000-000000000001','generationRunId','61420000-0000-4000-8000-000000000001','questionnaireSnapshotId','61250000-0000-4000-8000-000000000001','questionId','61230000-0000-4000-8000-000000000001','snapshotHash',repeat('6',64)),'[]'::jsonb)$$,'Retry with the same immutable input is idempotent');
select is((select count(*)::integer from public.generation_candidates where generation_run_id='61420000-0000-4000-8000-000000000001'),1,'Idempotent retry does not duplicate candidates');
select throws_ok($$select public.persist_generation_input('61aaaaaa-0000-4000-8000-000000000001','61420000-0000-4000-8000-000000000001',repeat('b',64),jsonb_build_object('tenantId','61aaaaaa-0000-4000-8000-000000000001','generationRunId','61420000-0000-4000-8000-000000000001','questionnaireSnapshotId','61250000-0000-4000-8000-000000000001','questionId','61230000-0000-4000-8000-000000000001','snapshotHash',repeat('6',64)),'[]'::jsonb)$$,'23505','Generation retry input does not match the immutable snapshot','Changed retry input is rejected');
select lives_ok($$select public.record_generation_usage('61aaaaaa-0000-4000-8000-000000000001','61420000-0000-4000-8000-000000000001','{"provider":"fake","model":"deterministic-fake-v1","inputTokens":0,"outputTokens":0,"latencyMs":1,"costMicroUsd":0,"attempt":1}')$$,'Provider usage can be recorded');
select lives_ok($$select public.record_generation_usage('61aaaaaa-0000-4000-8000-000000000001','61420000-0000-4000-8000-000000000001','{"provider":"fake","model":"deterministic-fake-v1","inputTokens":0,"outputTokens":0,"latencyMs":1,"costMicroUsd":0,"attempt":1}')$$,'Repeated provider usage recording is idempotent');
select is((select count(*)::integer from public.generation_provider_usage),1,'Idempotent usage recording creates one row');
select throws_ok($$update public.generation_provider_usage set latency_ms=2$$,'42501','Generation usage records are append-only','Provider usage cannot be mutated');
select lives_ok($$select public.fail_generation_run('61aaaaaa-0000-4000-8000-000000000001','61420000-0000-4000-8000-000000000002','provider_rate_limited','retry later',true)$$,'Retryable provider failure is persisted safely');
select is((select status::text from public.generation_runs where id='61420000-0000-4000-8000-000000000002'),'failed_retryable','Generation failure uses the typed retryable state');
select is((select status::text from public.jobs where id='61400000-0000-4000-8000-000000000002'),'failed_retryable','Job failure uses the typed retryable state');
set local role authenticated;
select set_config('request.jwt.claim.sub','61000000-0000-4000-8000-000000000001',true);
select set_config('request.jwt.claims','{"sub":"61000000-0000-4000-8000-000000000001","email":"runtime-alpha@example.test","role":"authenticated"}',true);
select lives_ok($$select public.cancel_generation_run('61aaaaaa-0000-4000-8000-000000000001','61420000-0000-4000-8000-000000000002')$$,'Requester can cancel an unfinished run');
reset role;
select * from finish();
rollback;
